import { Component } from '@angular/core';
import { FormControl, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { finalize, Subscription } from 'rxjs';
import { HttpService } from 'src/app/http.service';
import { allContacts } from '../contacts.interface';

import { Contact } from './add-Contact.interface';

@Component({
  selector: 'app-add-contact',
  templateUrl: './add-contact.component.html',
  styleUrls: ['./add-contact.component.scss']
})
export class AddContactComponent {
  allcontacts?:allContacts
  contact? : Contact;
  Form?: FormGroup;
  isSended= false;
  sub?: Subscription;


  buildForm(item?: Contact) {
    this.Form = new FormGroup({
        firstName: new FormControl('',[
            Validators.required,
        ]),
        lastName: new FormControl('',[
            Validators.required,
        ]),
        email: new FormControl('',[
            Validators.required,
        ]),
        phone: new FormControl('',[
          Validators.required,
        ]),
        address: new FormControl('',[
        Validators.required,
    ]),
    });
}

addContact(){
  const sub = this.http.post<Contact[]>("addContacts", this.Form?.value).pipe(finalize(() => {
      if (sub?.unsubscribe) {
          sub.unsubscribe();
      }
  })).subscribe(data => {
      this.isSended = true;
      this.router.navigate(['/contacts']);

  });
}

getContact(id: string) {
  const sub = this.http.get<allContacts>(`contact/${id}`).subscribe(item => {
      this.contact = item;
      this.buildForm(item);
      sub.unsubscribe();
  });
}


constructor (private router: Router, private http:HttpService, private route: ActivatedRoute){

  this.sub = this.route.params.subscribe(params => {
    if (params['id']) {
        this.getContact(params['id']);
    } else {
        this.buildForm();
    }
});
}


 ngOnInit() {


 }

}


<h1> איש קשר חדש</h1>

<form >
    <div class="field">
        <label><i class="fa fa-user"></i> שם פרטי:</label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="firstName">
    </div>

    <div class="field">
        <label><i class="fa fa-envelope"></i>   שם משפחה:</label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="lastName">
    </div>

    <div class="field">
        <label><i class="fa fa-user"></i>   אימייל:  </label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="email">
    </div>

    <div class="field">
        <label><i class="fa fa-asterisk"></i> טלפון:</label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="phone">
    </div>

    <div class="field">
        <label><i class="fa far fa-address-book"></i> כתובת:  </label>
        <input class="w3-input w3-border w3-round" type="text" formControlName="address">
    </div>


    <button class="w3-btn w3-green w3-round w3-block"  (click)="addContact()"  routerLink="/contacts">צור לקוח <i class="fa fa-check"></i></button>



</form>
